#include <stdio.h>

int findSingle(int nums[], int n) {
    int left = 0, right = n - 1;
    while (left < right) {
        int mid = left + (right - left) / 2;
        if (mid % 2 == 1) mid--; // make mid even
        if (nums[mid] == nums[mid + 1]) {
            left = mid + 2; // unique is after this pair
        } else {
            right = mid; // unique is at mid or before
        }
    }
    return nums[left];
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int nums[n];
        for (int i = 0; i < n; ++i) {
            scanf("%d", &nums[i]);
        }
        printf("%d\n", findSingle(nums, n));
    }
    return 0;
}

